import{_ as e,c as i,o as t,ae as a}from"./chunks/framework.BJMxTLS0.js";const p=JSON.parse('{"title":"Horizon OC","description":"","frontmatter":{},"headers":[],"relativePath":"homebrew/horizon-oc.md","filePath":"homebrew/horizon-oc.md"}'),r={name:"homebrew/horizon-oc.md"};function n(s,o,l,c,h,u){return t(),i("div",null,[...o[0]||(o[0]=[a('<h1 id="horizon-oc" tabindex="-1">Horizon OC <a class="header-anchor" href="#horizon-oc" aria-label="Permalink to &quot;Horizon OC&quot;">​</a></h1><p>Horizon OC is a <a href="./index.html#terminologies">sysmodule</a> that allows you to overclock the hardware of your Switch. The usage, configuration and clock speed information can be found on the official Github repository <a href="https://github.com/Horizon-OC/Horizon-OC" target="_blank" rel="noreferrer">here</a></p><h2 id="installation-requirements" tabindex="-1">Installation requirements: <a class="header-anchor" href="#installation-requirements" aria-label="Permalink to &quot;Installation requirements:&quot;">​</a></h2><ul><li>An archive manager like <a href="https://www.7-zip.org/" target="_blank" rel="noreferrer">7-Zip</a></li><li>The latest release of <a href="https://github.com/Horizon-OC/Horizon-OC/releases" target="_blank" rel="noreferrer">Horizon OC</a> (the <code>dist.zip</code> file)</li></ul><h2 id="installation-instructions" tabindex="-1">Installation instructions: <a class="header-anchor" href="#installation-instructions" aria-label="Permalink to &quot;Installation instructions:&quot;">​</a></h2><ol><li><p>Boot into hekate and go to <code>Tools</code> &gt; <code>USB Tools</code> &gt; <code>SD Card</code>, then plug your Switch into your PC via USB.</p></li><li><p>Your microSD card should now be accessible on your PC, open it.</p></li><li><p>Extract the <code>.zip</code> file to a location on your computer.</p><ul><li>If your archive manager allows for it, you can also simply open the <code>.zip</code> file directly.</li></ul></li><li><p>Copy the <em>contents</em> of the (extracted) <code>.zip</code> file to the root of your microSD card.</p></li><li><p>Edit <code>hekate_ipl.ini</code> to include these lines under your boot entries:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>kip1=atmosphere/kips/hoc.kip</span></span></code></pre></div></li><li><p>Boot into CFW.</p></li><li><p>Follow the <a href="https://rentry.co/erista" target="_blank" rel="noreferrer">Erista guide</a> or <a href="https://rentry.co/mariko" target="_blank" rel="noreferrer">Mariko guide</a></p></li></ol><h2 id="basic-usage-instructions" tabindex="-1">Basic usage instructions <a class="header-anchor" href="#basic-usage-instructions" aria-label="Permalink to &quot;Basic usage instructions&quot;">​</a></h2><p>Open Ultrahand and select Horizon OC Zeus, and configure your settings according to the guide</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="my-switch-crashes-on-boot-after-i-installed-horizon-oc-and-or-shows-a-black-screen" tabindex="-1">My Switch crashes on boot after I installed horizon-oc and/or shows a black screen!: <a class="header-anchor" href="#my-switch-crashes-on-boot-after-i-installed-horizon-oc-and-or-shows-a-black-screen" aria-label="Permalink to &quot;My Switch crashes on boot after I installed horizon-oc and/or shows a black screen!:&quot;">​</a></h3><p><strong>Cause:</strong> If your Switch crashes on boot, make sure you&#39;re using the latest release of horizon-oc. If it continues to crash afterwards, see the troubleshooting step at the bottom of this page.</p><h2 id="my-switch-crashes-while-using-horizon-oc" tabindex="-1">My Switch crashes while using Horizon-OC!: <a class="header-anchor" href="#my-switch-crashes-while-using-horizon-oc" aria-label="Permalink to &quot;My Switch crashes while using Horizon-OC!:&quot;">​</a></h2><p><strong>Cause:</strong> Your overclock settings may be unstable.</p><h2 id="horizon-oc-isn-t-working" tabindex="-1">Horizon-OC isn&#39;t working!: <a class="header-anchor" href="#horizon-oc-isn-t-working" aria-label="Permalink to &quot;Horizon-OC isn&#39;t working!:&quot;">​</a></h2><p>Assuming you&#39;ve followed the installation instructions successfully, this is probably due to the archive bit being set on one or more folders/files on your microSD card. This is usually the result of copying files to a microSD card via a Mac. If you are experiencing this issue, try running the archive bit fixer utility via hekate for all files.</p><p>This can be done by booting into hekate and going to <code>Tools</code> &gt; <code>Arch bit • RCM Touch • Pkg1/2</code> &gt; <code>Fix Archive Bit</code>.</p>',16)])])}const g=e(r,[["render",n]]);export{p as __pageData,g as default};
